// Acquire Lock with TTL - FASE 1.1
// Input: { provider_id, start_time, lock_duration_minutes? }
// Output: { success, lock_id, acquired, message, expires_at }

const input = $input.first().json;

// Validación de input
if (!input.provider_id || !input.start_time) {
  throw new Error('Missing required fields: provider_id, start_time');
}

const lockDuration = input.lock_duration_minutes || 5; // Default 5 min TTL
const lockKey = `lock_${input.provider_id}_${input.start_time}`;

return [{
  json: {
    provider_id: input.provider_id,
    start_time: input.start_time,
    lock_key: lockKey,
    expires_at: `NOW() + INTERVAL '${lockDuration} minutes'`,
    lock_duration_minutes: lockDuration
  }
}];

// Standard Contract Output for Lock System
const input = $input.first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      lock_id: input.lock_id,
      lock_key: input.lock_key,
      acquired_at: input.acquired_at,
      expires_at: input.expires_at,
      is_valid: input.is_valid !== false
    },
    _meta: {
      source: 'WF7_DISTRIBUTED_LOCK_SYSTEM',
      timestamp: new Date().toISOString(),
      version: '1.1.0'
    }
  }
}];
